class Solution:
    def longestCommonSubpath(self, n, paths):
        def has(L):
            if L == 0:
                return True
            common = None
            for p in paths:
                if len(p) < L:
                    return False
                wins = set()
                for i in range(len(p) - L + 1):
                    wins.add(tuple(p[i:i + L]))
                if common is None:
                    common = wins
                else:
                    common &= wins
                if not common:
                    return False
            return bool(common)
        lo, hi = 0, min(len(p) for p in paths)
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if has(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

