        MOD1 = (1 << 61) - 1
        BASE1 = 131542391
        MOD2 = 1000000007
        BASE2 = 1000003
        minlen = min(len(p) for p in paths)
        def windows(p, L):
            s = set()
            h1 = 0
            h2 = 0
            p1 = pow(BASE1, L, MOD1)
            p2 = pow(BASE2, L, MOD2)
            for i in range(L):
                h1 = (h1 * BASE1 + p[i] + 1) % MOD1
                h2 = (h2 * BASE2 + p[i] + 1) % MOD2
            s.add((h1, h2))
            for i in range(L, len(p)):
                h1 = (h1 * BASE1 + p[i] + 1 - (p[i - L] + 1) * p1) % MOD1
                h2 = (h2 * BASE2 + p[i] + 1 - (p[i - L] + 1) * p2) % MOD2
