var longestCommonSubpath = function(n, paths) {
    const MOD2 = 1000000007n;
    const BASE2 = 1000003n;
    const MOD3 = 998244353n;
    const BASE3 = 1000033n;
    let minlen = Infinity;
    for (const p of paths) minlen = Math.min(minlen, p.length);
    function powmod(b, e, m) {
        let r = 1n; b %= m;
        while (e > 0n) { if (e & 1n) r = r * b % m; b = b * b % m; e >>= 1n; }
        return r;
    }
    function windows(p, L) {
        const s = new Set();
        let h2 = 0n, h3 = 0n;
        const p2 = powmod(BASE2, BigInt(L), MOD2);
        const p3 = powmod(BASE3, BigInt(L), MOD3);
        for (let i = 0; i < L; i++) {
            h2 = (h2 * BASE2 + BigInt(p[i] + 1)) % MOD2;
            h3 = (h3 * BASE3 + BigInt(p[i] + 1)) % MOD3;
        }
        s.add(h2.toString() + '_' + h3.toString());
        for (let i = L; i < p.length; i++) {
            h2 = (h2 * BASE2 + BigInt(p[i] + 1) - BigInt(p[i - L] + 1) * p2 % MOD2 + MOD2 * MOD2) % MOD2;
            h3 = (h3 * BASE3 + BigInt(p[i] + 1) - BigInt(p[i - L] + 1) * p3 % MOD3 + MOD3 * MOD3) % MOD3;
            s.add(h2.toString() + '_' + h3.toString());
        }
        return s;
    }
    function has(L) {
        if (L === 0) return true;
        let common = null;
        for (const p of paths) {
            if (p.length < L) return false;
            const w = windows(p, L);
            if (common === null) common = w;
            else {
                const nc = new Set();
                for (const k of w) if (common.has(k)) nc.add(k);
                common = nc;
            }
            if (common.size === 0) return false;
        }
        return common.size > 0;
    }
    let lo = 0, hi = minlen, ans = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (has(mid)) { ans = mid; lo = mid + 1; } else { hi = mid - 1; }
    }
    return ans;
};
